<?php
namespace App\Models;
use App\Models\Concerns\BelongsToWorkspace;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;
class Task extends Model{use BelongsToWorkspace,SoftDeletes;public const STATUSES=['new','todo','in_progress','review','completed','reopened','hold','cancelled'];public const PRIORITIES=['low','medium','high','urgent'];protected $fillable=['workspace_id','task_number','title','description','task_category_id','project_id','department_id','team_id','created_by','priority','status','start_date','due_date','estimated_hours','completed_at','completed_by','proof_required','approval_required','approval_status'];protected function casts():array{return['start_date'=>'date','due_date'=>'date','completed_at'=>'datetime','estimated_hours'=>'decimal:2','proof_required'=>'boolean','approval_required'=>'boolean'];}public function category(){return $this->belongsTo(TaskCategory::class,'task_category_id');}public function project(){return $this->belongsTo(Project::class);}public function department(){return $this->belongsTo(Department::class);}public function team(){return $this->belongsTo(Team::class);}public function creator(){return $this->belongsTo(User::class,'created_by');}public function assignees(){return $this->hasMany(TaskAssignee::class);}public function assignedUsers(){return $this->belongsToMany(User::class,'task_assignees')->withPivot(['role','assigned_by','assigned_at'])->withTimestamps();}public function watchers(){return $this->belongsToMany(User::class,'task_watchers')->withTimestamps();}public function checklistItems(){return $this->hasMany(TaskChecklist::class)->orderBy('sort_order');}public function comments(){return $this->hasMany(TaskComment::class)->latest();}public function attachments(){return $this->hasMany(TaskAttachment::class)->latest();}public function activityLogs(){return $this->hasMany(TaskActivityLog::class)->latest();}}
